{
  "terms": [
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety system designed to quickly cut off power during a fault to prevent electric shock.",
      "anchor": "The 'safety net' that trips the breaker when things go wrong.",
      "misconception": "Thinking ADS is a single component; it is actually a system made of conductors and protective devices working together."
    },
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth conductors are separate throughout the entire system.",
      "anchor": "The 'S' stands for Separate.",
      "misconception": "Believing the earth and neutral are joined at the consumer unit in this system."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "A system where neutral and earth are combined in the supply cable but separated at the property intake.",
      "anchor": "The 'C' for Combined (in the street) and 'S' for Separate (in the house).",
      "misconception": "Thinking it is identical to TN-S just because it provides an earth terminal to the user."
    },
    {
      "term": "TT System",
      "simpleDefinition": "A system where the installation is connected to earth via a local electrode (rod) rather than a supplier's earth.",
      "anchor": "Relies on the ground itself to complete the fault path.",
      "misconception": "Assuming every property has an earth rod; most modern urban homes use the supplier's cable instead."
    },
    {
      "term": "Circuit Protective Conductor (CPC)",
      "simpleDefinition": "The specific wire that connects the metal parts of a circuit to the main earthing terminal.",
      "anchor": "The green-and-yellow wire inside a standard circuit cable.",
      "misconception": "Confusing the CPC with the main earthing conductor that goes to the supplier's intake."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's main earth terminal to the means of earthing.",
      "anchor": "The 'master' earth wire at the service head.",
      "misconception": "Thinking this is the same as the smaller CPCs found in individual circuits."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors used to connect metal service pipes (like water or gas) to the main earthing terminal.",
      "anchor": "Connecting the 'services' to earth to keep them at the same voltage.",
      "misconception": "Thinking bonding is designed to carry fault current from a faulty appliance; its job is to stop voltage differences between pipes and metalwork."
    },
    {
      "term": "Supplementary Bonding",
      "simpleDefinition": "Additional bonding used in high-risk areas, like bathrooms, to connect touchable metal parts together.",
      "anchor": "Extra 'local' bonding for added safety in wet zones.",
      "misconception": "Believing supplementary bonding is required in every room of a building."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod, plate, or mesh driven into the ground to provide a physical connection to Earth.",
      "anchor": "The 'spike' in the garden used for TT systems.",
      "misconception": "Thinking an electrode is needed for TN-S or TN-C-S systems."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component like a fuse or circuit breaker that automatically opens the circuit during a fault.",
      "anchor": "The part that actually 'breaks' the circuit to stop the flow of electricity.",
      "misconception": "Thinking the earth wire itself stops the current; the wire only provides the path that allows the device to trip."
    }
  ],
